  ('aboriginal-c5fb3965-moex-00208', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列題辭之使用，何者不恰當？', '["壽慶：道範長存", "喬遷：里仁為美", "婚嫁：桃夭及時", "入營：移孝作忠"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00209', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列匾額，使用正確的選項是：', '["中醫診所：杏壇春暖", "農場種植：功在桑梓", "立法委員：克孚眾望", "報館開業：陶朱媲美"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00210', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列選項中，何者適用於對他人稱呼自己的幼輩如「弟」、「姪」之前？', '["家", "舍", "敝", "愚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00211', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '關於書信的啟封詞，下列敘述何者正確？', '["對平輩可用「安啟」", "對長輩可用「台啟」", "對師長可用「道啟」", "寫明信片可用「啟」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00212', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列「」中的語詞，何者不是傳說中的神馬或良駒？', '["「飛黃」騰達", "「騏驥」一躍，不能十步", "「赤兔」思念舊主，絕食而死", "「金烏」玉兔最無情，驅馳不暫停"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00213', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「八荒霍霍驚仰首，空中□□逐日走。拔山倒海事事終，不追白日非英雄！果然手捉黃金烏，問公此 樂胡為乎？如何口渴顏色槁，一枝杖作鄧林草？」□□中所詠神話英雄為：', '["夸父", "刑天", "精衛", "盤古"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00214', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '司馬遷《史記．太史公自序》中記錄一段他父親的〈論六家要旨〉：「□□使人精神專一，動合無形， 贍足萬物。其為術也，因陰陽之大順，采儒墨之善，撮名法之要，與時遷移，應物變化。立俗施事， 無所不宜； 指約而易操，事少而功多。」上文中□□應填入的學派是：', '["法家", "名家", "道家", "雜家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00215', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「你一直說要求仙，求俠／是崑崙太遠了，就近向你的酒瓶／去尋找邋遢俠和糊塗仙嗎？／——啊呀 要小心，好險哪／超這種貨櫃車可不是兒戲／慢一點吧，慢一點，我求求你／這幾年交通意外的統計 ／不下於安史之亂的傷亡／這跑天下呀究竟不是天馬／跑高速公路也不是行空／速限哪，我的謫仙， 是九十公里／你怎麼開到一百四了？」上述詩句為作者想像與某位詩人同遊高速公路，這位詩人應是：', '["陶潛", "李白", "李賀", "杜牧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00216', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「朱泙漫學屠龍於支離益，單千金之家。三年技成而無所用其巧。」上文所闡述學習之理應是：', '["勤學好問", "學而不厭", "學以致用", "勤學苦練"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00217', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「守河防敵卒當先，將鎮中央馬兩邊。此日鴻溝分楚漢，英雄割據待他年。」 詩中所描述的是何種民俗遊藝？', '["兵棋", "圍棋", "麻將", "象棋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
